if __name__ == "__main__":
    import json, os
    os.makedirs("schemes", exist_ok=True)
    for key, data, label in [
        ("sports", SPORTS_SCHEMES, "Sports"),
        ("digital_india", DIGITAL_INDIA_SCHEMES, "Digital India"),
        ("fisheries", FISHERIES_SCHEMES, "Fisheries"),
    ]:
        with open(f"schemes/{key}.json", "w", encoding="utf-8") as f:
            json.dump({"sector": key, "schemes": data}, f, ensure_ascii=False, indent=2)
        print(f"✅ {label}: {len(data)} schemes → schemes/{key}.json")
    total = len(SPORTS_SCHEMES) + len(DIGITAL_INDIA_SCHEMES) + len(FISHERIES_SCHEMES)
    print(f"\n🎉 Added {total} schemes across 3 new sectors")
